import{_ as s,o as n,c as t,ag as p}from"./chunks/framework.DXGyWiRo.js";const h=JSON.parse('{"title":"Chat Completions","description":"","frontmatter":{},"headers":[],"relativePath":"docs/use/api/chat_completions.md","filePath":"docs/use/api/chat_completions.md","lastUpdated":null}'),e={name:"docs/use/api/chat_completions.md"};function o(i,a,l,u,c,r){return n(),t("div",null,[...a[0]||(a[0]=[p(`<h1 id="chat-completions" tabindex="-1">Chat Completions <a class="header-anchor" href="#chat-completions" aria-label="Permalink to &quot;Chat Completions&quot;">​</a></h1><ul><li>Endpoint：<code>POST /v1/chat/completions</code></li><li>Base URL：<code>https://api.maisi-ai.com/v1</code></li><li>鉴权：<code>Authorization: Bearer &lt;your-api-key&gt;</code></li><li>API 参考： <ul><li>Maisi：<code>/v1/chat/completions</code>（见 <a href="https://api-docs.maisi-ai.com/api-297251415.md" target="_blank" rel="noreferrer">API 文档</a>）</li><li>OpenAI 官方：<a href="https://platform.openai.com/docs/api-reference/chat/create" target="_blank" rel="noreferrer">https://platform.openai.com/docs/api-reference/chat/create</a></li></ul></li></ul><h2 id="文本请求" tabindex="-1">文本请求 <a class="header-anchor" href="#文本请求" aria-label="Permalink to &quot;文本请求&quot;">​</a></h2><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --request POST \\</span></span>
<span class="line"><span>  --url https://api.maisi-ai.com/v1/chat/completions \\</span></span>
<span class="line"><span>  --header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>  --header &#39;Authorization: Bearer &lt;your-api-key&gt;&#39; \\</span></span>
<span class="line"><span>  --data &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;gpt-4o-mini&quot;,</span></span>
<span class="line"><span>    &quot;messages&quot;: [</span></span>
<span class="line"><span>      {&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Write a one-sentence bedtime story about a unicorn.&quot;}</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }&#39;</span></span></code></pre></div><h2 id="多模态-图像输入" tabindex="-1">多模态（图像输入） <a class="header-anchor" href="#多模态-图像输入" aria-label="Permalink to &quot;多模态（图像输入）&quot;">​</a></h2><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --request POST \\</span></span>
<span class="line"><span>  --url https://api.maisi-ai.com/v1/chat/completions \\</span></span>
<span class="line"><span>  --header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>  --header &#39;Authorization: Bearer &lt;your-api-key&gt;&#39; \\</span></span>
<span class="line"><span>  --data &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;gpt-4.1&quot;,</span></span>
<span class="line"><span>    &quot;messages&quot;: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        &quot;role&quot;: &quot;user&quot;,</span></span>
<span class="line"><span>        &quot;content&quot;: [</span></span>
<span class="line"><span>          {&quot;type&quot;: &quot;text&quot;, &quot;text&quot;: &quot;What is in this image?&quot;},</span></span>
<span class="line"><span>          {&quot;type&quot;: &quot;image_url&quot;, &quot;image_url&quot;: {&quot;url&quot;: &quot;https://upload.wikimedia.org/wikipedia/commons/thumb/d/dd/Gfp-wisconsin-madison-the-nature-boardwalk.jpg/2560px-Gfp-wisconsin-madison-the-nature-boardwalk.jpg&quot;}}</span></span>
<span class="line"><span>        ]</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;max_tokens&quot;: 300</span></span>
<span class="line"><span>  }&#39;</span></span></code></pre></div><h2 id="流式-sse" tabindex="-1">流式（SSE） <a class="header-anchor" href="#流式-sse" aria-label="Permalink to &quot;流式（SSE）&quot;">​</a></h2><p>将请求体中的 <code>stream</code> 设为 <code>true</code>：</p><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --request POST \\</span></span>
<span class="line"><span>  --url https://api.maisi-ai.com/v1/chat/completions \\</span></span>
<span class="line"><span>  --header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>  --header &#39;Authorization: Bearer &lt;your-api-key&gt;&#39; \\</span></span>
<span class="line"><span>  --data &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;gpt-4o-mini&quot;,</span></span>
<span class="line"><span>    &quot;stream&quot;: true,</span></span>
<span class="line"><span>    &quot;messages&quot;: [</span></span>
<span class="line"><span>      {&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Say hello in 3 short sentences.&quot;}</span></span>
<span class="line"><span>    ]</span></span>
<span class="line"><span>  }&#39;</span></span></code></pre></div><p>返回为 SSE 数据流（<code>chat.completion.chunk</code>）。常见终止信号是某个 chunk 出现 <code>finish_reason: &quot;stop&quot;</code>。</p><h2 id="函数调用-tools" tabindex="-1">函数调用（Tools） <a class="header-anchor" href="#函数调用-tools" aria-label="Permalink to &quot;函数调用（Tools）&quot;">​</a></h2><p>bash</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>curl --request POST \\</span></span>
<span class="line"><span>  --url https://api.maisi-ai.com/v1/chat/completions \\</span></span>
<span class="line"><span>  --header &#39;Content-Type: application/json&#39; \\</span></span>
<span class="line"><span>  --header &#39;Authorization: Bearer &lt;your-api-key&gt;&#39; \\</span></span>
<span class="line"><span>  --data &#39;{</span></span>
<span class="line"><span>    &quot;model&quot;: &quot;gpt-4.1&quot;,</span></span>
<span class="line"><span>    &quot;messages&quot;: [</span></span>
<span class="line"><span>      {&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;What is the weather like in Boston today?&quot;}</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;tools&quot;: [</span></span>
<span class="line"><span>      {</span></span>
<span class="line"><span>        &quot;type&quot;: &quot;function&quot;,</span></span>
<span class="line"><span>        &quot;function&quot;: {</span></span>
<span class="line"><span>          &quot;name&quot;: &quot;get_current_weather&quot;,</span></span>
<span class="line"><span>          &quot;description&quot;: &quot;Get the current weather in a given location&quot;,</span></span>
<span class="line"><span>          &quot;parameters&quot;: {</span></span>
<span class="line"><span>            &quot;type&quot;: &quot;object&quot;,</span></span>
<span class="line"><span>            &quot;properties&quot;: {</span></span>
<span class="line"><span>              &quot;location&quot;: {&quot;type&quot;: &quot;string&quot;, &quot;description&quot;: &quot;The city and state, e.g. San Francisco, CA&quot;},</span></span>
<span class="line"><span>              &quot;unit&quot;: {&quot;type&quot;: &quot;string&quot;, &quot;enum&quot;: [&quot;celsius&quot;, &quot;fahrenheit&quot;]}</span></span>
<span class="line"><span>            },</span></span>
<span class="line"><span>            &quot;required&quot;: [&quot;location&quot;]</span></span>
<span class="line"><span>          }</span></span>
<span class="line"><span>        }</span></span>
<span class="line"><span>      }</span></span>
<span class="line"><span>    ],</span></span>
<span class="line"><span>    &quot;tool_choice&quot;: &quot;auto&quot;</span></span>
<span class="line"><span>  }&#39;</span></span></code></pre></div><h2 id="相关内容" tabindex="-1">相关内容 <a class="header-anchor" href="#相关内容" aria-label="Permalink to &quot;相关内容&quot;">​</a></h2><ul><li>图片生成：见 <a href="/docs/use/api/images.html">Images</a></li><li>音频（Whisper/TTS）：见 <a href="/docs/use/api/audio.html">Audio</a></li><li>接口兼容（chat vs responses）：见 <a href="/docs/use/chat.html">接口兼容</a></li><li>推理模型与推理参数：见 <a href="/docs/use/reasoning.html">推理设置</a></li><li>常见错误排查：见 <a href="/docs/error.html">常见错误以及解决办法</a></li></ul>`,18)])])}const d=s(e,[["render",o]]);export{h as __pageData,d as default};
